var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"우, 우왓!","JPN":"わ、わっ！","ENG":"W-whoa!","TWN":"哇！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아하하…… 이, 이건 나 혼자서는 도저히…….","JPN":"あはは……こ、これは私一人では無理かも……","ENG":"Ahaha... I-I can’t handle this all by myself...","TWN":"哈哈哈……我自己是要怎麼……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그쪽 여성 분!! 제 뒤로 오세요!!","JPN":"そちらの女性の方！！　私の後ろに来てください！！","ENG":"You, over there! Get behind me!!","TWN":"那位小姐！！請到我身後來！！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다행이다……. 늦지 않았네요.","JPN":"よかった……間に合ったようですね。","ENG":"Thank goodness... What a close call.","TWN":"好險……還來得及。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다치진 않으셨어요?","JPN":"お怪我はありませんか？","ENG":"Are you okay?","TWN":"你沒受傷吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"수, 순식간에…… 해치워버렸어……!!","JPN":"あ、あっという間に……やっつけた……！！","ENG":"S-she took them out so easily...!!","TWN":"立…立刻……就處理掉咧……！！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"고맙습니다, 멋진 언니……! 저도 언니처럼 되고 싶어요!","JPN":"ありがとうございます、素敵なお姉さん……！\\n私もお姉さんみたいになりたいですっ！","ENG":"Thank you...! I want to be like you someday!","TWN":"謝謝你，帥氣的姊姊……！我也想跟姊姊一樣！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_NULL","text":{"KOREA":"아가씨……. 왜 저를…….","JPN":"お嬢様……なぜ私を……","ENG":"Miss Jia... W-why did you...?","TWN":"小姐……為什麼要救我……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GUARD_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님은 직원의 일도 자기 일처럼 생각하라고 하셨거든요.","JPN":"お祖父様は、社員のことは自分の事のように考えなさいとおっしゃいました。","ENG":"Grandfather said to treat employees how I would want them to treat me.","TWN":"我爺爺有說，要把員工的事當成自己的事。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 다치기 싫은 것처럼, 대장님도 다치기 싫으셨을 거예요.","JPN":"私が怪我をしたくないように、隊長も怪我をしたくないはずだと思っただけです。","ENG":"Much like I dislike getting hurt, I bet you wouldn’t like it as well.","TWN":"我不想受傷的話，那你應該也不想受傷吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"네…… 네가 날 살린 건가? 윽……!","JPN":"お……お前が私を助けたのか？　うっ……！","ENG":"Y-you... saved me? Ngh...!","TWN":"是……你救了我的嗎？嗚……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"총알이 어깨를 스쳐 지나갔어요. 다행히 큰 부상은 아니네요.","JPN":"弾丸が肩をかすめています。\\n幸い、大事に至るような怪我ではありません。","ENG":"The bullet grazed your shoulder. Luckily, it’s not fatal.","TWN":"子彈劃過你的肩膀，幸好沒有大礙。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"……고맙군. 내가 큰 착각을 하고 있었어.","JPN":"……ありがとう。私は大きな勘違いをしていたようだ。","ENG":"Thank you... It seems that I was wrong about you.","TWN":"……謝謝你，我誤會你了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"언니……?","JPN":"お姉さん……？","ENG":"Hello...? Miss?","TWN":"姊姊……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"喔！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니에요. 민간인을 도울 수 있어서 저도 고마운 걸요.","JPN":"いいえ、民間人の方を助けられて、私も嬉しいです。","ENG":"Sorry about that. It’s always nice to help out civilians in need.","TWN":"別客氣，我也很開心可以幫到平民老百姓。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 저보다 더 언니실 걸요?","JPN":"あと、お姉さんは私のほうじゃないと思いますよ？","ENG":"And you don’t have to call me Miss.","TWN":"另外，你年紀應該比我大吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"저도 민간인이 아니긴 한데…….","JPN":"一応、私も民間人じゃないのですが……","ENG":"Well, I’m not a civilian either...","TWN":"我也不是平民老百姓……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"23:35 ARC-KP1 \\n알파트릭스 본사, 부회장실.","JPN":"23:35 ARC-KP1 \\nアルファトリックス本社、副会長室。","ENG":"23:35 ARC-KP1\\nAlphatrix HQ, Vice Chairman Office","TWN":"23:35 ARC-KP1\\n阿爾法崔克斯總公司，副會長辦公室。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"비서실을 떠난 뒤로는 두 번 다시 여기 올 일 없을 거라고 생각했는데…….","JPN":"秘書室を離れてから、二度とここに来ることはないと思っていたのに……","ENG":"I never expected to revisit this place after leaving the Secretary's Office...","TWN":"我以為離開秘書室後，就不會再回到這裡……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":" 이런 일 때문에 오게 될 줄은…….","JPN":"こんなことで来るとは……","ENG":"Who knew I’d be here because of this...","TWN":"而且竟然是因為這種事……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"실장, 나는 자네보다 더 오랫동안 그 괴물을 지켜봐 왔어.","JPN":"室長、私は君よりも長い間あの化け物を見守ってきた。","ENG":"I’ve known that monster longer than you have, Ms. Lee.","TWN":"李室長，我認識那個怪物的時間比你還久。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"형님이 세상을 떠난 뒤로 내가 쓸 수 있는 수단은 모두 써서, 그 괴물에 대해 조사했지.","JPN":"兄が亡くなった後、あらゆる手段であの化け物について調べた。","ENG":"When my brother died, I did everything in my power to research about that thing.","TWN":"自從大哥過世後，我便用盡一切方法來調查那個怪物。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그리고 마침내 그 괴물을 이 세상에서 매장해 버릴 수 있는 실마리를 손에 넣은 걸세.","JPN":"そして、ついにあの化け物を葬る手掛かりを手に入れたのだ。","ENG":"Now, I finally found a way to turn the world against that monster.","TWN":"最後終於得到可以將那個怪物，埋葬在這個世界裡的線索。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……단서가 있다면 여기뿐이야.","JPN":"……手掛かりがあるとしたら、ここしかない。","ENG":"If there’s evidence, it has to be here somewhere.","TWN":"……線索應該就在這裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 날 봤던, 아가씨와 같은 얼굴을 가진 범인…….","JPN":"あの日見た、お嬢様と同じ顔をした犯人……","ENG":"The killer with Miss Jia’s face I saw that night...","TWN":"有著和小姐一樣容貌的犯人……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그리고 헤비암즈의 공장에서 생산된 대량의 밸런스 브레이커…….","JPN":"そしてヘビーアームズの工場で生産された大量のバランスブレイカー……","ENG":"The mass production of Balance Breakers at the Heavyarms factory...","TWN":"重武裝工廠大量製造的平衡破壞者……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아무리 생각해도 아가씨와 똑같은 사람이 여럿이라고밖에 생각할 수 없어.","JPN":"どう考えても、お嬢様と同じ人間が複数いるとしか思えない。","ENG":"I can only assume that there are more who look exactly like Miss Jia.","TWN":"總覺得，和小姐長得一樣的人應該有很多個。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"범인이 부회장님을 노린 까닭은…… 분명 그 비밀을 알고 계셨기 때문이야.","JPN":"犯人が副会長を狙った理由は……きっとその秘密を知っていたから。","ENG":"The reason why Vice Chairman was a target is... because he knew something about it.","TWN":"而犯人之所以要對副會長下手……應該是因為副會長知道那個祕密的關係。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"평소에 서류를 두시던 장소에는……. 역시 없나.","JPN":"普段書類を保管していた場所には……やっぱりないか。","ENG":"I guess there’s nothing where he used to put all his documents...","TWN":"平常放資料的地方……沒有？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"후우……. 사직서나 쓸 시간에 대체 무슨 짓을 하고 있는 건지…….","JPN":"ふう……辞職届を書かなきゃいけないのに何をやってるのかしら、私……","ENG":"Ugh... What am I doing? I should be writing up my resignation letter right now...","TWN":"真的是……我不寫辭呈，在這裡幹什麼……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……음?","JPN":"……うん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그러고 보니 저 액자……. 내가 비서실에 처음 발령됐을 때부터 있었지.","JPN":"そういえばあの額縁……私が秘書室に初めて入った時からあったわね。","ENG":"That frame... It’s been there ever since I was assigned to the Secretary’s Office.","TWN":"那個畫框……從我被派到祕書室時就在了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……이상하네. 옆 부분만 먼지 한 톨 없이 깨끗해.","JPN":"……おかしい。横の部分だけ埃が溜まっていない。","ENG":"That’s odd... There isn’t any dust on its sides.","TWN":"……奇怪，就只有邊邊很乾淨，一點灰塵也有。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"설마 했는데 정말 비밀 책장이었다니……. 어린애 같은 구석도 있으셨네. ","JPN":"まさかと思ったけど本当に秘密ドアだったなんて……\\n副会長って子どもみたいな遊び心があったのね。","ENG":"Should’ve known there was a secret bookcase... Didn't think he’d have a childish side to him.","TWN":"竟然還真的有秘密書櫃……怎麼像小朋友一樣愛藏東西。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"특이점 프로젝트? 회장님이 살아 계실 때 진행된 건가……?","JPN":"特異点プロジェクト？　会長の生前に進行されていたもの……？","ENG":"Singularity Project? Was it something they worked on when the President was still alive?","TWN":"奇異點計畫？這是會長在世時執行的計畫嗎……？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"인간이라는 종의 혁신……. 가능성의 실체화……","JPN":"人間という種の革新……可能性の実体化……","ENG":"Innovation of the Human Race... Proof of concept...","TWN":"人類的革新……實現可能……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이게 다……. 무슨 허무맹랑한 소리야?","JPN":"これはいったい……なんてデタラメな話なの？","ENG":"What’s... all this nonsense about?","TWN":"這……是在胡說八道什麼？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"저런. 자기도 카운터면서 허무맹랑하다는 표현은 너무한데.","JPN":"あらまあ、自分もカウンターのくせにデタラメなんて表現はひどいわね。","ENG":"Oh... Being a Counter yourself and calling it nonsense sounds too hypocritical, no?","TWN":"怎麼這樣，明明自己也是制裁者，竟然說這是胡說八道？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"누구냐!","JPN":"誰だ！","ENG":"Who’s there?!","TWN":"是誰！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"이야, 오빠도 참 재치 있어. 나는 그런 줄도 모르고 엉뚱한 곳만 찾아다녔잖아.","JPN":"ふふ、兄さんもセンスあるわね。\\n私ったら、それも知らずに違う所ばかり探し回っちゃったじゃない。","ENG":"Wow... Didn’t think my brother would be this clever. And here I’ve been wasting my time trying to find it.","TWN":"哇，大哥城府真深，竟然把東西藏在這裡，害我都找不到！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"역시 전직 비서는 다르네. 나보다 오빠에 대해 더 잘 알고 있어.","JPN":"やっぱり元秘書は違うわね。私より兄さんのことをよく知ってる。","ENG":"Should’ve just gone straight to you. You seem to know my brother better than I do, having been his secretary and all.","TWN":"真不愧是秘書，比我更了解大哥呢！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 케케묵은 서류 뭉치만 없어지면, 특이점 프로젝트는 세상에 노출될 일이 없지.","JPN":"その古い書類さえなくなれば、特異点プロジェクトが\\n世間に公表されることもなくなる。","ENG":"The only thing that would reveal the Singularity Project to the rest of the world is that old pile of documents. And it must be destroyed.","TWN":"只要把那堆資料毀屍滅跡，奇異點計畫就無法曝光在世人眼前！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"찾는 수고를 덜어 줘서 고마워. 역시 지난번 일은 내게 절호의 기회였어.","JPN":"探す手間を省いてくれてありがとう。\\nやっぱりこの前のことは私にとって絶好のチャンスだったわ。","ENG":"Thanks for going through the trouble of finding it for me. I knew last time was the perfect opportunity for me.","TWN":"我還得謝謝你幫我找到呢～上次的事對我而言，果然是個大好機會。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"너는…… 아가씨를 따라다니던……?","JPN":"あなたは……お嬢様に付きまとっていた……？","ENG":"You’re... the one that was following Miss Jia...?","TWN":"你……是和小姐一起的……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 원래 계획에서 조금 틀어지긴 했지만…….","JPN":"まあ、元の計画から少しずれてしまったけど……","ENG":"Oh well. It did cause some hiccups in my plan, but...","TWN":"雖然和原本的計畫有點不一樣……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"기왕 움직여 준 거, 나를 위해 <color=#ffd34c>한 칸</color>만 더 움직여 줄래?","JPN":"せっかく動いてくれたんだし、私のためにもう<color=#ffd34c>1マス</color>だけ動いてくれる？","ENG":"If you’re going to make your move, how about moving <color=#ffd34c>a space</color> for me?","TWN":"既然你已經幫我走到這裡，那可以再幫我多走<color=#ffd34c>一格</color>嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"너! 네가 설마 지금까지 아가씨를……!","JPN":"あなたは！　まさかこれまでお嬢様を……！","ENG":"You! Were you the one that...?!","TWN":"你！你該不會一直……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……훌륭한 미끼로 써줄 테니까.","JPN":"……立派な餌にしてあげる。","ENG":"...You’ll be the perfect bait.","TWN":"……我會好好利用你這個誘餌的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"}}}}]`);export{e as default};